import{_ as e,o as s,c as n,O as r}from"./chunks/framework.92cbe775.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/materials/case-studies.md","filePath":"en/materials/case-studies.md","lastUpdated":1776068451000}'),i={name:"en/materials/case-studies.md"};function t(l,a,c,o,d,p){return s(),n("div",null,a[0]||(a[0]=[r('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Showroom</p><h1>Case Studies / End-to-End Execution Examples</h1><div class="brand-hero__panel"><span class="brand-pill">Flagship Cases</span><strong>This page is not a hello demo. It is three end-to-end execution examples that can be used directly in conversations about projects, governance, and delivery.</strong><p>The point is not that a script can run. The point is how ExecGov turns a complex flow into a service that can be requested, confirmed, executed, and reviewed later.</p></div><p class="brand-lead"> These examples serve two purposes: they show the current product direction, and they help potential customers make a fast judgment about whether <strong>this platform can turn complex, risky, multi-person script workflows into a formal entry point</strong>. </p><div class="brand-chip-list"><span class="brand-chip">K8s security inspection</span><span class="brand-chip">Cross-cloud cost analysis</span><span class="brand-chip">Operations data automation</span><span class="brand-chip">End-to-end execution</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="../contact.html#lead-form">Bring a real scenario</a><a class="cta-button" href="../product/index.html">View Product Overview</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECGOV // CASE STUDIES</span><span>MAT 08</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">flow</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">request</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">confirm</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">execute</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">record</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">who</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">when</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">result</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">asset</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">python_first</span></span></div><div class="matrix-panel__callout">SHOW WHAT CONTROLLED EXECUTION LOOKS LIKE</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">type</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">showroom</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">goal</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">project fit</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">mode</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">end-to-end</span></span></div></div></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Case 01</p><h2>Automatically inspect a K8s cluster and generate a security report</h2><p>Best for showing how a high-risk inspection flow can close the loop across confirmation, execution, traceability, and report return.</p></article><article class="brand-card"><p class="brand-kicker">Case 02</p><h2>Cross-cloud cost analysis and optimization recommendations</h2><p>Best for showing how multi-source data pull, cleaning, aggregation, analysis, and recommendation output can become one governed entry point.</p></article><article class="brand-card"><p class="brand-kicker">Case 03</p><h2>Operations data automation and anomaly tracking</h2><p>Best for showing how the most common spreadsheet, reporting, import/export, and exception-tracking flows in teams can be brought under unified governance.</p></article></section><section id="k8s-security-report" class="brand-card"><p class="brand-kicker">Case 01</p><h2>Automatically inspect a K8s cluster and generate a security report</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>Typical problem</h3><ul class="brand-list"><li>There are many inspection scripts, but they are scattered across servers and personal accounts.</li><li>It is unclear who is allowed to run them, when they were run, and which commands were actually executed.</li><li>When something goes wrong, there is no unified report or review entry.</li></ul></article><article class="brand-card brand-card--nested"><h3>How ExecGov handles it</h3><ul class="brand-list"><li>A user submits a request to inspect a production cluster and generate a security report.</li><li>AI matches the inspection Skill and the platform displays the inspection scope and risk notes.</li><li>High-risk node checks require confirmation first, then call Python scripts for execution.</li><li>The result returns as a structured report, risk summary, and execution log.</li></ul></article><article class="brand-card brand-card--nested"><h3>Governance points</h3><ul class="brand-list"><li>Limit which clusters can be touched by tenant, role, and environment.</li><li>Put high-risk commands behind a confirmation node instead of allowing direct execution.</li><li>Record who initiated the run, who confirmed it, and which checks were executed.</li></ul></article><article class="brand-card brand-card--nested"><h3>Final deliverables</h3><ul class="brand-list"><li>K8s security inspection report</li><li>Execution logs and anomaly summary</li><li>Reviewable audit records and a download entry</li></ul></article></div></section><section id="multi-cloud-cost-analysis" class="brand-card"><p class="brand-kicker">Case 02</p><h2>Cross-cloud cost analysis and optimization recommendations</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>Typical problem</h3><ul class="brand-list"><li>Different cloud vendors expose bills in different formats, so manual consolidation is expensive.</li><li>The analysis scripts and rules are scattered and hard to reuse reliably.</li><li>Every month the team repeats the same cleaning, aggregation, comparison, and recommendation work.</li></ul></article><article class="brand-card brand-card--nested"><h3>How ExecGov handles it</h3><ul class="brand-list"><li>One unified entry triggers &quot;generate this month&#39;s cross-cloud cost analysis.&quot;</li><li>The platform pulls authorized cloud bills and resource ledgers.</li><li>Python scripts perform cleaning, aggregation, anomaly detection, and recommendation generation.</li><li>The result returns an analysis report, cost breakdown, and recommendation list.</li></ul></article><article class="brand-card brand-card--nested"><h3>Governance points</h3><ul class="brand-list"><li>Limit which accounts, billing periods, and resource ranges can be read.</li><li>Record the data sources, rule versions, and script versions used for each analysis.</li><li>Keep the result report and execution context for reconciliation and later review.</li></ul></article><article class="brand-card brand-card--nested"><h3>Final deliverables</h3><ul class="brand-list"><li>Cross-cloud cost analysis report</li><li>Anomalous cost details and optimization recommendations</li><li>Traceable execution records and version information</li></ul></article></div></section><section id="ops-data-automation" class="brand-card"><p class="brand-kicker">Case 03</p><h2>Operations data automation and anomaly tracking</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>Typical problem</h3><ul class="brand-list"><li>Teams export, clean, and merge multiple Excel or CSV files every day.</li><li>Anomalies are still checked by hand, so the work is repetitive and easy to get wrong.</li><li>Results are scattered across chat threads and local folders, which makes handover difficult.</li></ul></article><article class="brand-card brand-card--nested"><h3>How ExecGov handles it</h3><ul class="brand-list"><li>Upload the raw files through one unified entry and choose the process template.</li><li>The platform schedules Python scripts to clean, summarize, compare, and detect anomalies.</li><li>The result returns a standard report, anomaly list, and handling suggestions.</li><li>The whole chain remains reviewable, which makes it suitable for collaboration and handover.</li></ul></article><article class="brand-card brand-card--nested"><h3>Governance points</h3><ul class="brand-list"><li>Limit which file types, file sizes, and process scopes can be uploaded.</li><li>Record the input files, script versions, and output artifacts for each run.</li><li>Govern risky write operations separately from read-only analysis flows.</li></ul></article><article class="brand-card brand-card--nested"><h3>Final deliverables</h3><ul class="brand-list"><li>Standardized output report</li><li>Anomaly details and handling suggestions</li><li>File download entry and execution ledger</li></ul></article></div></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Step</p><h2>If you already have workflows that look like these</h2><p class="brand-lead">The most direct move is to compare one real workflow against these three examples, decide which input, risk, and result pattern it matches, and then choose whether to move into a design-partner discussion.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="../contact.html#lead-form"><span>Partner</span><strong>Apply as a design partner</strong></a><a class="brand-link-card" href="./why-execgov.html"><span>Why</span><strong>Why I Am Building ExecGov</strong></a><a class="brand-link-card" href="../product/index.html"><span>Product</span><strong>Product Overview</strong></a></div></div></section></div>',1)]))}const m=e(i,[["render",t]]);export{u as __pageData,m as default};
